# Cross-provider multimodal abstraction layer
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Any
import asyncio, time

@dataclass
class MultimodalMessage:
    role: str
    content: list[dict]  # [{type: "text", text: "..."}, {type: "image", path: "...", detail: "low"}]

@dataclass
class ProviderResponse:
    text: str
    latency_ms: float
    cost: float
    model: str
    tokens: dict


class MultimodalProvider(ABC):
    """Abstract base for multimodal providers."""

    @abstractmethod
    async def complete(self, msg: MultimodalMessage, **kwargs) -> ProviderResponse:
        pass

    @abstractmethod
    def estimate_cost(self, msg: MultimodalMessage) -> float:
        pass

    @property
    @abstractmethod
    def model_name(self) -> str:
        pass


class OpenAIProvider(MultimodalProvider):
    def __init__(self, api_key: str, model="gpt-4o"):
        from openai import AsyncOpenAI
        self.client = AsyncOpenAI(api_key=api_key)
        self._model = model

    async def complete(self, msg: MultimodalMessage, **kwargs) -> ProviderResponse:
        start = time.time()
        openai_content = []
        for block in msg.content:
            if block["type"] == "text":
                openai_content.append({"type": "text", "text": block["text"]})
            elif block["type"] == "image":
                import base64
                with open(block["path"], "rb") as f:
                    b64 = base64.b64encode(f.read()).decode()
                openai_content.append({
                    "type": "image_url",
                    "image_url": {
                        "url": f"data:image/png;base64,{b64}",
                        "detail": block.get("detail", "auto")
                    }
                })
        response = await self.client.chat.completions.create(
            model=self._model,
            messages=[{"role": msg.role, "content": openai_content}],
            **kwargs
        )
        latency = (time.time() - start) * 1000
        choice = response.choices[0]
        return ProviderResponse(
            text=choice.message.content,
            latency_ms=latency,
            cost=self.estimate_cost(msg),
            model=self._model,
            tokens={"input": response.usage.prompt_tokens,
                    "output": response.usage.completion_tokens}
        )

    def estimate_cost(self, msg: MultimodalMessage) -> float:
        tokens = self._count_tokens(msg)
        return (tokens / 1_000_000) * 2.50

    def _count_tokens(self, msg: MultimodalMessage) -> int:
        total = 0
        for block in msg.content:
            if block["type"] == "text":
                total += len(block["text"]) // 4
            elif block["type"] == "image":
                detail = block.get("detail", "auto")
                total += 85 if detail == "low" else 170
        return total

    @property
    def model_name(self) -> str:
        return self._model


class GeminiProvider(MultimodalProvider):
    def __init__(self, api_key: str, model="gemini-1.5-pro"):
        import google.genai as genai
        self.client = genai.Client(api_key=api_key)
        self._model = model

    async def complete(self, msg: MultimodalMessage, **kwargs) -> ProviderResponse:
        start = time.time()
        contents = []
        for block in msg.content:
            if block["type"] == "text":
                contents.append(block["text"])
            elif block["type"] == "image":
                from PIL import Image
                img = Image.open(block["path"])
                contents.append(img)
        response = self.client.models.generate_content(
            model=self._model, contents=contents
        )
        latency = (time.time() - start) * 1000
        return ProviderResponse(
            text=response.text,
            latency_ms=latency,
            cost=self.estimate_cost(msg),
            model=self._model,
            tokens=self._parse_usage(response)
        )

    def estimate_cost(self, msg: MultimodalMessage) -> float:
        tokens = self._count_tokens(msg)
        return (tokens / 1_000_000) * 1.25  # Gemini is cheaper

    def _count_tokens(self, msg: MultimodalMessage) -> int:
        total = 0
        for block in msg.content:
            if block["type"] == "text":
                total += len(block["text"]) // 4
            elif block["type"] == "image":
                total += 258  # Gemini's average tokens per image
        return total

    def _parse_usage(self, response) -> dict:
        return {"input": 0, "output": 0}

    @property
    def model_name(self) -> str:
        return self._model


class MultimodalRouter:
    """Routes multimodal requests across providers with fallback."""
    def __init__(self, providers: list[MultimodalProvider]):
        self.providers = providers
        self.failures: dict[str, int] = {}
        self.circuit_breaker_threshold = 3

    async def route(self, msg: MultimodalMessage, **kwargs) -> ProviderResponse:
        """Try providers in order, with circuit breaker."""
        errors = []
        for provider in self.providers:
            pname = provider.model_name
            if self.failures.get(pname, 0) >= self.circuit_breaker_threshold:
                errors.append(f"{pname}: circuit open")
                continue
            try:
                return await provider.complete(msg, **kwargs)
            except Exception as e:
                self.failures[pname] = self.failures.get(pname, 0) + 1
                errors.append(f"{pname}: {e}")
                continue
        raise Exception(f"All providers failed: {'; '.join(errors)}")

    def cheapest_provider(self, msg: MultimodalMessage) -> MultimodalProvider:
        return min(self.providers, key=lambda p: p.estimate_cost(msg))
